// 1. Sadə array: Eyni tipdə dəyərlər
let prices: number[] = [10, 20, 30]; // Yalnız rəqəmlər
// prices.push("40"); // Xəta: string number[] tipinə uyğun deyil

// Alternativ sintaksis
let names: Array<string> = ["Murad", "Alice"]; // Yalnız sətirlər
// names.push(123); // Xəta: number string[] tipinə uyğun deyil

// 2. Tuple: Sabit uzunluqlu siyahı
type ProductInfo = [string, number]; // Ad və qiymət
let product: ProductInfo = ["Laptop", 1200];
// product = [1200, "Laptop"]; // Xəta: tiplər düzgün sırayla deyil

// 3. Readonly array: Dəyişdirilməz siyahı
let fixedNumbers: readonly number[] = [1, 2, 3];
// fixedNumbers.push(4); // Xəta: readonly array dəyişdirilə bilməz

// 4. Funksiyalarda array types
function getFirstPrice(prices: number[]): number | undefined {
  return prices.length > 0 ? prices[0] : undefined;
}
console.log(getFirstPrice(prices)); // Çıxış: 10

// 5. Tuple ilə funksiya
type User = [string, number];
function showUser(user: User): string {
  return `${user[0]}: ${user[1]} yaş`;
}
const user: User = ["Murad", 23];
console.log(showUser(user)); // Çıxış: Murad: 23 yaş

// Sadə mağaza sistemi
let productPrices: number[] = [1200, 25, 50]; // Məhsul qiymətləri
let productNames: string[] = ["Laptop", "Mouse", "Keyboard"]; // Məhsul adları

type Product = [string, number]; // Məhsul adı və qiyməti
let product: Product = ["Mouse", 25];

function showProducts(prices: number[]): string {
  return `Məhsulların qiymətləri: ${prices.join(", $")}`;
}

console.log(showProducts(productPrices)); // Çıxış: Məhsulların qiymətləri: 1200, $25, $50
console.log(`${product[0]}: $${product[1]}`); // Çıxış: Mouse: $25

