// 1. Simple array: Same-type values
let prices: number[] = [10, 20, 30]; // Only numbers
// prices.push("40"); // Error: string is not number[] type

// Alternative syntax
let names: Array<string> = ["Murad", "Alice"]; // Only strings
// names.push(123); // Error: number is not string[] type

// 2. Tuple: Fixed-length list
type ProductInfo = [string, number]; // Name and price
let product: ProductInfo = ["Laptop", 1200];
// product = [1200, "Laptop"]; // Error: types are in wrong order

// 3. Readonly array: Immutable list
let fixedNumbers: readonly number[] = [1, 2, 3];
// fixedNumbers.push(4); // Error: readonly array cannot be modified

// 4. Array types in functions
function getFirstPrice(prices: number[]): number | undefined {
  return prices.length > 0 ? prices[0] : undefined;
}
console.log(getFirstPrice(prices)); // Output: 10

// 5. Tuple in functions
type User = [string, number];
function showUser(user: User): string {
  return `${user[0]}: ${user[1]} years old`;
}
const user: User = ["Murad", 23];
console.log(showUser(user)); // Output: Murad: 23 years old

// Simple store system
let productPrices: number[] = [1200, 25, 50]; // Product prices
let productNames: string[] = ["Laptop", "Mouse", "Keyboard"]; // Product names

type Product = [string, number]; // Product name and price
let product: Product = ["Mouse", 25];

function showProducts(prices: number[]): string {
  return `Product prices: ${prices.join(", $")}`;
}

console.log(showProducts(productPrices)); // Output: Product prices: 1200, $25, $50
console.log(`${product[0]}: $${product[1]}`); // Output: Mouse: $25

