// 1. Простой массив: Значения одного типа
let prices: number[] = [10, 20, 30]; // Только числа
// prices.push("40"); // Ошибка: строка не соответствует типу number[]

// Альтернативный синтаксис
let names: Array<string> = ["Murad", "Alice"]; // Только строки
// names.push(123); // Ошибка: число не соответствует типу string[]

// 2. Кортеж: Список фиксированной длины
type ProductInfo = [string, number]; // Название и цена
let product: ProductInfo = ["Laptop", 1200];
// product = [1200, "Laptop"]; // Ошибка: типы в неправильном порядке

// 3. Readonly массив: Неизменяемый список
let fixedNumbers: readonly number[] = [1, 2, 3];
// fixedNumbers.push(4); // Ошибка: readonly массив не может быть изменён

// 4. Array types в функциях
function getFirstPrice(prices: number[]): number | undefined {
  return prices.length > 0 ? prices[0] : undefined;
}
console.log(getFirstPrice(prices)); // Вывод: 10

// 5. Кортеж в функциях
type User = [string, number];
function showUser(user: User): string {
  return `${user[0]}: ${user[1]} лет`;
}
const user: User = ["Murad", 23];
console.log(showUser(user)); // Вывод: Murad: 23 лет

